import { useState, useEffect } from 'react'
import Sidebar from './components/Sidebar'
import Dashboard from './components/Dashboard'
import Campaigns from './components/Campaigns'
import Agents from './components/Agents'
import Settings from './components/Settings'
import ProfileComponent from './components/Profile'
import { supabase } from './supabaseClient'
import type { StudentLead, Campaign, Agent, LeadStatus, Profile } from './types'
import './index.css'
import { ToastProvider } from './components/Toast'
import OnboardingTour from './components/OnboardingTour'
import { PopupProvider } from './components/Popup'
import { Menu, X, Target } from 'lucide-react';
import type { Session } from '@supabase/supabase-js'
import Auth from './components/Auth'
import Provisioner from './components/Provisioner'
import Leads from './components/Leads'
import Pipeline from './components/Pipeline'
import ActivateAccount from './components/ActivateAccount'

function App() {
  const [session, setSession] = useState<Session | null>(null)
  const [activeTab, setActiveTab] = useState(localStorage.getItem('crm_active_tab') || 'dashboard')
  const [isSidebarOpen, setIsSidebarOpen] = useState(false)
  const [dashboardStatusFilter, setDashboardStatusFilter] = useState('all')
  const [dashboardCampaignFilter, setDashboardCampaignFilter] = useState('all')

  // DARYL EMERGENCY PASS (Mode Expert) 👔 ✨
  const [isDarylBypass, setIsDarylBypass] = useState(false);

  useEffect(() => {
    localStorage.setItem('crm_active_tab', activeTab);
  }, [activeTab]);

  const [leads, setLeads] = useState<StudentLead[]>([])
  const [campaigns, setCampaigns] = useState<Campaign[]>([])
  const [agents, setAgents] = useState<Agent[]>([])
  const [statuses, setStatuses] = useState<LeadStatus[]>([])
  const [profile, setProfile] = useState<Profile | null>(null)
  const [loading, setLoading] = useState(true)

  const fetchData = async (currentSession = session) => {
    // If Daryl Bypass is ON, we force Admin profile
    if (isDarylBypass) {
      const darylProfile = {
        id: 'ea7346fb-0667-4221-8288-c8d17ade53a9', // Ton ID réel
        organization_id: '00000000-0000-0000-0000-000000000000',
        organization_name: 'ESCEN CRM',
        full_name: 'Daryl - Direction ESCEN',
        role: 'admin' as const,
        email: 'darylggt23@gmail.com'
      };
      setProfile(darylProfile);
      // On continue le chargement des données même en bypass Daryl ! ✨
    } else {
      if (!currentSession?.user) return;
    }

    setLoading(true)
    try {
      let currentProfile: Profile | null = null;
      if (!isDarylBypass && currentSession?.user) {
        const { data: idProfile, error: profileErr } = await supabase.from('profiles').select('*').eq('id', currentSession.user.id).maybeSingle();
        if (profileErr) console.error("Error fetching profile:", profileErr);
        currentProfile = idProfile as Profile | null;

        if (currentProfile) {
          currentProfile = {
            id: currentProfile.id,
            organization_id: currentProfile.organization_id,
            organization_name: 'ESCEN CRM',
            full_name: currentProfile.full_name,
            role: currentProfile.role,
            email: currentProfile.email,
            must_change_password: currentProfile.must_change_password
          };
        }

        if (currentProfile?.must_change_password) {
          setActiveTab('profile');
        }
        setProfile(currentProfile);
      }

      const { data: statusesData } = await supabase.from('lead_statuses').select('*').order('label');
      if (statusesData) {
        setStatuses(statusesData.map(s => ({
          id: s.id as string,
          label: s.label as string,
          color: s.color as string,
          isDefault: s.is_default as boolean,
          sortOrder: s.sort_order as number
        })));
      }

      let leadsQuery = supabase.from('leads').select('*').order('created_at', { ascending: false });

      const effectiveProfile = isDarylBypass ? { id: 'ea73...', role: 'admin' } : currentProfile;

      if (effectiveProfile?.role === 'agent') {
        leadsQuery = leadsQuery.eq('agent_id', effectiveProfile.id);
      }

      const { data: leadsData } = await leadsQuery;
      const { data: campaignsData } = await supabase.from('campaigns').select('*');
      const { data: agentsData } = await supabase.from('profiles').select('*');

      if (leadsData) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        setLeads((leadsData as unknown[]).map((l: any) => ({
          id: l.id,
          organizationId: l.organization_id,
          campaignId: l.campaign_id,
          agentId: l.agent_id,
          statusId: l.status_id,
          firstName: l.first_name,
          lastName: l.last_name,
          email: l.email,
          phone: l.phone || '',
          country: l.country || '',
          city: l.city || '',
          fieldOfInterest: l.field_of_interest,
          level: l.study_level,
          score: l.score || 0,
          notes: l.notes,
          metadata: l.metadata,
          lastInteractionAt: l.last_interaction_at,
          createdAt: l.created_at,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          status: ((statusesData || []) as any[]).find(s => s.id === l.status_id),
          interactions: []
        })) as StudentLead[]);
      }

      if (campaignsData) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        setCampaigns((campaignsData as unknown[]).map((c: any) => ({
          id: c.id,
          organizationId: c.organization_id,
          name: c.name,
          source: c.source,
          budget: c.budget,
          startDate: c.start_date,
          endDate: c.end_date,
          isActive: c.is_active,
          column_mappings: c.column_mappings
        })) as Campaign[]);
      }

      if (agentsData) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const mappedAgents = (agentsData as any[])
          .filter((a) => a.role === 'agent')
          .map(a => {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const agentLeads = ((leadsData || []) as any[]).filter((l) => l.agent_id === a.id);
            return {
              id: a.id,
              organizationId: a.organization_id,
              name: a.full_name || a.email?.split('@')[0] || 'Agent',
              email: a.email || '',
              role: a.role,
              capacityWeight: a.capacity_weight || 1,
              isActive: a.is_active ?? true,
              leadsAssigned: agentLeads.length,
              overdueTasksCount: 0,
              conversionRate: 0,
              avgResponseTime: 0
            };
          });
        setAgents(mappedAgents);
      }

    } catch (err) {
      console.error("Fetch error:", err);
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    const isBypass = localStorage.getItem('daryl_emergency_bypass') === 'true';
    if (isBypass) {
      setIsDarylBypass(true);
      fetchData();
    }

    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session)
      if (session) fetchData(session);
    })

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      setSession(session)
      if (event === 'PASSWORD_RECOVERY') setActiveTab('profile');
      if (session) {
        fetchData(session);
        if (session.user && !isDarylBypass) {
          const { data: p } = await supabase.from('profiles').select('must_change_password').eq('id', session.user.id).single();
          if (p?.must_change_password) setActiveTab('profile');
        }
      } else if (!isDarylBypass) {
        setLeads([]);
        setProfile(null);
        setLoading(false);
      }
    })

    return () => subscription.unsubscribe()
  }, [isDarylBypass])

  if (loading && !session && !isDarylBypass) {
    return (
      <div className="loading-screen">
        <div className="loader-container"><div className="loader-rings"></div></div>
        <div className="loading-text">ESCEN CRM</div>
      </div>
    );
  }

  if (!session && !isDarylBypass) {
    const urlParams = new URLSearchParams(window.location.search);
    if (urlParams.has('token')) {
      return (
        <ToastProvider>
          <ActivateAccount />
        </ToastProvider>
      );
    }
    return (
      <ToastProvider>
        <Auth />
      </ToastProvider>
    );
  }

  return (
    <ToastProvider>
      <PopupProvider>
        <OnboardingTour />
        <div className="mobile-header">
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <div style={{ width: '32px', height: '32px', background: 'linear-gradient(135deg, var(--primary), var(--accent))', borderRadius: '8px', display: 'grid', placeItems: 'center' }}>
              <Target size={18} color="white" />
            </div>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 700 }}>ESCEN CRM</h2>
          </div>
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} style={{ background: 'transparent', border: 'none', color: 'white' }}>
            {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>

        <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
          <Sidebar activeTab={activeTab} profile={profile} setActiveTab={(tab) => { setActiveTab(tab); setIsSidebarOpen(false); }} />
        </div>

        <main className="main-content">
          {activeTab === 'dashboard' && <Dashboard leads={leads} campaigns={campaigns} statuses={statuses} setActiveTab={setActiveTab} setStatusFilter={setDashboardStatusFilter} selectedCampaignId={dashboardCampaignFilter} setSelectedCampaignId={setDashboardCampaignFilter} />}
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          {activeTab === 'pipeline' && <Pipeline profile={profile} leads={leads} setLeads={setLeads as any} campaigns={campaigns} agents={agents} statuses={statuses} />}
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          {activeTab === 'leads' && <Leads leads={leads} setLeads={setLeads as any} statuses={statuses} campaigns={campaigns} onRefresh={() => fetchData(session)} initialStatusFilter={dashboardStatusFilter} onFilterChange={setDashboardStatusFilter} initialCampaignFilter={dashboardCampaignFilter} onCampaignChange={setDashboardCampaignFilter} />}
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          {activeTab === 'campaigns' && <Campaigns profile={profile} campaigns={campaigns} setCampaigns={setCampaigns} leads={leads} setLeads={setLeads as any} agents={agents} onRefresh={() => fetchData(session)} />}
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          {activeTab === 'agents' && profile?.role === 'admin' && <Agents profile={profile} agents={agents} leads={leads} setLeads={setLeads as any} campaigns={campaigns} statuses={statuses} onRefresh={() => fetchData(session)} />}
          {activeTab === 'settings' && profile?.role === 'admin' && <Settings />}
          {activeTab === 'profile' && <ProfileComponent profile={profile} leads={leads} statuses={statuses} onUpdate={() => fetchData(session)} />}
          {activeTab === 'provisioner' && profile?.role === 'admin' && profile?.email === 'darylggt23@gmail.com' && <Provisioner />}
        </main>
      </PopupProvider>
    </ToastProvider>
  );
}

export default App;
